import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';

const CATEGORIES = {
  mentalHealth: {
    id: 'mentalHealth',
    name: 'Mental Health',
    color: '#6366f1',
    hoverColor: '#5558e3',
    lightColor: 'rgba(99, 102, 241, 0.1)',
    placeholder: "What's on your mind today?",
    fieldLabel: null,
    fieldPlaceholder: null,
    emptyMessage: 'No entries yet',
    emptySubtext: 'Start writing to create your first entry'
  },
  school: {
    id: 'school',
    name: 'School & Studies',
    color: '#0ea5e9',
    hoverColor: '#0284c7',
    lightColor: 'rgba(14, 165, 233, 0.1)',
    placeholder: 'What did you learn today?',
    fieldLabel: 'Subject or Topic',
    fieldPlaceholder: 'Subject or Topic (optional)',
    emptyMessage: 'No notes yet',
    emptySubtext: 'Start documenting your learning journey'
  },
  personal: {
    id: 'personal',
    name: 'Personal Favorites',
    color: '#f59e0b',
    hoverColor: '#d97706',
    lightColor: 'rgba(245, 158, 11, 0.1)',
    placeholder: 'What made you smile today?',
    fieldLabel: 'Title',
    fieldPlaceholder: 'Give it a title (optional)',
    emptyMessage: 'No memories yet',
    emptySubtext: 'Start capturing your favorite moments'
  }
};

function JournalNotebook() {
  const [tailwindLoaded, setTailwindLoaded] = useState(false);
  const [entries, setEntries] = useStorage('entries', []);
  const [activeCategory, setActiveCategory] = useState('mentalHealth');
  const [currentEntry, setCurrentEntry] = useState('');
  const [currentField, setCurrentField] = useState('');
  const [editingId, setEditingId] = useState(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    if (!document.getElementById('tailwind-script')) {
      const tailwindScript = document.createElement('script');
      tailwindScript.id = 'tailwind-script';
      tailwindScript.src = 'https://cdn.tailwindcss.com';
      tailwindScript.onload = () => {
        setTimeout(() => setTailwindLoaded(true), 100);
      };
      document.head.appendChild(tailwindScript);
    } else {
      setTailwindLoaded(true);
    }
  }, []);

  useEffect(() => {
    document.body.style.background = '#ffffff';
    document.documentElement.style.minHeight = '100%';
    return () => { 
      document.body.style.background = ''; 
      document.documentElement.style.minHeight = ''; 
    };
  }, []);

  const category = CATEGORIES[activeCategory];

  const filteredEntries = useMemo(() => {
    return entries.filter(e => e.category === activeCategory).sort((a, b) => b.createdAt - a.createdAt);
  }, [entries, activeCategory]);

  const handleSave = useCallback(() => {
    if (!currentEntry.trim()) return;

    if (editingId) {
      setEntries(prev => prev.map(entry => 
        entry.id === editingId 
          ? { ...entry, content: currentEntry, field: currentField, updatedAt: Date.now() }
          : entry
      ));
      setEditingId(null);
    } else {
      const newEntry = {
        id: Date.now().toString(),
        category: activeCategory,
        content: currentEntry,
        field: currentField,
        createdAt: Date.now(),
        updatedAt: Date.now()
      };
      setEntries(prev => [newEntry, ...prev]);
    }
    setCurrentEntry('');
    setCurrentField('');
    textareaRef.current?.focus();
  }, [currentEntry, currentField, editingId, activeCategory, setEntries]);

  const handleEdit = useCallback((entry) => {
    setCurrentEntry(entry.content);
    setCurrentField(entry.field || '');
    setEditingId(entry.id);
    textareaRef.current?.focus();
  }, []);

  const handleDelete = useCallback((id) => {
    setEntries(prev => prev.filter(entry => entry.id !== id));
    if (editingId === id) {
      setCurrentEntry('');
      setCurrentField('');
      setEditingId(null);
    }
  }, [editingId, setEntries]);

  const handleCancel = useCallback(() => {
    setCurrentEntry('');
    setCurrentField('');
    setEditingId(null);
  }, []);

  const handleCategoryChange = useCallback((categoryId) => {
    setActiveCategory(categoryId);
    setCurrentEntry('');
    setCurrentField('');
    setEditingId(null);
  }, []);

  const formatDate = useCallback((timestamp) => {
    const date = new Date(timestamp);
    const now = new Date();
    const isToday = date.toDateString() === now.toDateString();

    if (isToday) {
      return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
    }
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  }, []);

  if (!tailwindLoaded) {
    return <div style={{ padding: '20px', textAlign: 'center', fontFamily: 'Inter, -apple-system, sans-serif' }}>Loading...</div>;
  }

  return (
    <div style={{ fontFamily: 'Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, sans-serif', minHeight: '100vh' }}>
      {/* Header */}
      <div style={{ padding: '48px 48px 32px', borderBottom: '1px solid #f0f0f0' }}>
        <h1 style={{ fontSize: '32px', fontWeight: '300', color: '#1a1a1a', marginBottom: '8px', letterSpacing: '-0.02em' }}>
          Journal Notebook
        </h1>
        <p style={{ fontSize: '15px', color: '#666', fontWeight: '400' }}>
          Your personal space for mental health, learning, and favorite moments
        </p>
      </div>

      {/* Category Tabs */}
      <div style={{ padding: '32px 48px 0', borderBottom: '1px solid #f0f0f0' }}>
        <div style={{ display: 'flex', gap: '8px' }}>
          {Object.values(CATEGORIES).map(cat => (
            <button
              key={cat.id}
              onClick={() => handleCategoryChange(cat.id)}
              style={{
                padding: '14px 24px',
                fontSize: '15px',
                fontWeight: '500',
                border: 'none',
                borderBottom: activeCategory === cat.id ? `3px solid ${cat.color}` : '3px solid transparent',
                background: 'transparent',
                color: activeCategory === cat.id ? cat.color : '#666',
                cursor: 'pointer',
                transition: 'all 0.2s ease',
                marginBottom: '-1px'
              }}
              onMouseEnter={(e) => {
                if (activeCategory !== cat.id) {
                  e.target.style.color = '#333';
                }
              }}
              onMouseLeave={(e) => {
                if (activeCategory !== cat.id) {
                  e.target.style.color = '#666';
                }
              }}
            >
              {cat.name}
            </button>
          ))}
        </div>
      </div>

      {/* Entry Editor */}
      <div style={{ padding: '48px' }}>
        <div style={{ 
          background: '#ffffff', 
          borderRadius: '16px', 
          padding: '32px',
          boxShadow: '0 8px 32px rgba(0, 0, 0, 0.04)',
          marginBottom: '48px',
          border: `1px solid ${category.lightColor}`
        }}>
          {category.fieldLabel && (
            <input
              type="text"
              value={currentField}
              onChange={(e) => setCurrentField(e.target.value)}
              placeholder={category.fieldPlaceholder}
              style={{
                width: '100%',
                padding: '16px 20px',
                fontSize: '16px',
                fontWeight: '500',
                border: '1px solid #f0f0f0',
                borderRadius: '12px',
                fontFamily: 'inherit',
                color: '#1a1a1a',
                background: '#fafafa',
                outline: 'none',
                transition: 'all 0.2s ease',
                marginBottom: '16px'
              }}
              onFocus={(e) => {
                e.target.style.borderColor = category.color;
                e.target.style.background = '#ffffff';
              }}
              onBlur={(e) => {
                e.target.style.borderColor = '#f0f0f0';
                e.target.style.background = '#fafafa';
              }}
            />
          )}
          <textarea
            ref={textareaRef}
            value={currentEntry}
            onChange={(e) => setCurrentEntry(e.target.value)}
            placeholder={category.placeholder}
            style={{
              width: '100%',
              minHeight: '180px',
              padding: '20px',
              fontSize: '16px',
              lineHeight: '1.6',
              border: '1px solid #f0f0f0',
              borderRadius: '12px',
              resize: 'vertical',
              fontFamily: 'inherit',
              color: '#1a1a1a',
              background: '#fafafa',
              outline: 'none',
              transition: 'all 0.2s ease'
            }}
            onFocus={(e) => {
              e.target.style.borderColor = category.color;
              e.target.style.background = '#ffffff';
            }}
            onBlur={(e) => {
              e.target.style.borderColor = '#f0f0f0';
              e.target.style.background = '#fafafa';
            }}
          />
          <div style={{ display: 'flex', gap: '12px', marginTop: '20px', justifyContent: 'flex-end' }}>
            {editingId && (
              <button
                onClick={handleCancel}
                style={{
                  padding: '14px 28px',
                  fontSize: '15px',
                  fontWeight: '500',
                  border: '1px solid #e0e0e0',
                  borderRadius: '10px',
                  background: '#ffffff',
                  color: '#666',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease'
                }}
                onMouseEnter={(e) => e.target.style.background = '#f5f5f5'}
                onMouseLeave={(e) => e.target.style.background = '#ffffff'}
              >
                Cancel
              </button>
            )}
            <button
              onClick={handleSave}
              disabled={!currentEntry.trim()}
              style={{
                padding: '14px 32px',
                fontSize: '15px',
                fontWeight: '500',
                border: 'none',
                borderRadius: '10px',
                background: currentEntry.trim() ? category.color : '#e0e0e0',
                color: '#ffffff',
                cursor: currentEntry.trim() ? 'pointer' : 'not-allowed',
                transition: 'all 0.2s ease',
                boxShadow: currentEntry.trim() ? `0 4px 16px ${category.lightColor}` : 'none'
              }}
              onMouseEnter={(e) => {
                if (currentEntry.trim()) e.target.style.background = category.hoverColor;
              }}
              onMouseLeave={(e) => {
                if (currentEntry.trim()) e.target.style.background = category.color;
              }}
            >
              {editingId ? 'Update Entry' : 'Save Entry'}
            </button>
          </div>
        </div>

        {/* Entries List */}
        {filteredEntries.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '64px 32px', color: '#999' }}>
            <div style={{ fontSize: '18px', fontWeight: '400', marginBottom: '8px' }}>{category.emptyMessage}</div>
            <div style={{ fontSize: '14px', color: '#bbb' }}>{category.emptySubtext}</div>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            {filteredEntries.map(entry => (
              <div
                key={entry.id}
                style={{
                  background: '#ffffff',
                  borderRadius: '16px',
                  padding: '32px',
                  boxShadow: '0 4px 24px rgba(0, 0, 0, 0.03)',
                  transition: 'all 0.2s ease',
                  borderLeft: `4px solid ${category.color}`
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.boxShadow = '0 8px 32px rgba(0, 0, 0, 0.06)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.boxShadow = '0 4px 24px rgba(0, 0, 0, 0.03)';
                }}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
                  <div>
                    {entry.field && (
                      <div style={{ 
                        fontSize: '15px', 
                        fontWeight: '600', 
                        color: category.color, 
                        marginBottom: '4px' 
                      }}>
                        {entry.field}
                      </div>
                    )}
                    <div style={{ fontSize: '13px', color: '#999', fontWeight: '500' }}>
                      {formatDate(entry.createdAt)}
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button
                      onClick={() => handleEdit(entry)}
                      style={{
                        padding: '6px 14px',
                        fontSize: '13px',
                        fontWeight: '500',
                        border: '1px solid #f0f0f0',
                        borderRadius: '6px',
                        background: '#ffffff',
                        color: '#666',
                        cursor: 'pointer',
                        transition: 'all 0.2s ease'
                      }}
                      onMouseEnter={(e) => {
                        e.target.style.borderColor = category.color;
                        e.target.style.color = category.color;
                      }}
                      onMouseLeave={(e) => {
                        e.target.style.borderColor = '#f0f0f0';
                        e.target.style.color = '#666';
                      }}
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleDelete(entry.id)}
                      style={{
                        padding: '6px 14px',
                        fontSize: '13px',
                        fontWeight: '500',
                        border: '1px solid #f0f0f0',
                        borderRadius: '6px',
                        background: '#ffffff',
                        color: '#666',
                        cursor: 'pointer',
                        transition: 'all 0.2s ease'
                      }}
                      onMouseEnter={(e) => {
                        e.target.style.borderColor = '#ef4444';
                        e.target.style.color = '#ef4444';
                      }}
                      onMouseLeave={(e) => {
                        e.target.style.borderColor = '#f0f0f0';
                        e.target.style.color = '#666';
                      }}
                    >
                      Delete
                    </button>
                  </div>
                </div>
                <div style={{ 
                  fontSize: '15px', 
                  lineHeight: '1.7', 
                  color: '#333',
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-word'
                }}>
                  {entry.content}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default JournalNotebook;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar.jsx';
import NavigationBar from './components/NavigationBar.jsx';
import KMeansVisualization from './components/KMeansVisualization.jsx';
import ElbowChart from './components/ElbowChart.jsx';
import InertiaChart from './components/InertiaChart.jsx';
import LinearRegressionVisualization from './components/LinearRegressionVisualization.jsx';
import ResidualPlot from './components/ResidualPlot.jsx';
import PredictedVsActual from './components/PredictedVsActual.jsx';
import {
  initializeCentroids,
  assignPointsToClusters,
  updateCentroids,
  calculateInertia,
  calculateElbowData
} from './utils/kmeans.js';
import {
  calculateMSE,
  calculateRMSE,
  calculateMAE,
  calculateR2,
  generateRandomPoints as generateLRPoints,
  calculateOptimalLine,
  generateLinearPoints,
  gradientDescentStep
} from './utils/linearRegression.js';

function MLVisualization() {
  const [currentView, setCurrentView] = useState('home'); // 'home', 'kmeans', or 'linear-regression'

  // K-Means state
  const [points, setPoints] = useState([]);
  const [centroids, setCentroids] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [k, setK] = useState(3);
  const [learningRate, setLearningRate] = useState(1.0);
  const [gdSpeed, setGdSpeed] = useState(1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [iteration, setIteration] = useState(0);
  const [inertiaHistory, setInertiaHistory] = useState([]);
  const [phase, setPhase] = useState('idle'); // 'assignment', 'update', 'idle'
  const [initializationMode, setInitializationMode] = useState('random'); // 'random' or 'kmeans++'
  const [hasStartedClustering, setHasStartedClustering] = useState(false);

  // Elbow data
  const [elbowData, setElbowData] = useState([]);
  const [isCalculatingElbow, setIsCalculatingElbow] = useState(false);

  // Animation timer
  const animationTimerRef = useRef(null);
  const isProcessingRef = useRef(false);

  useEffect(() => {
    document.body.style.background = '#ffffff';
    document.documentElement.style.minHeight = '100%';
    return () => {
      document.body.style.background = '';
      document.documentElement.style.minHeight = '';
    };
  }, []);

  // Initialize with random points
  const generateRandomPoints = useCallback((count = 100) => {
    const LOGICAL_WIDTH = 800;
    const LOGICAL_HEIGHT = 600;

    const newPoints = [];
    for (let i = 0; i < count; i++) {
      newPoints.push([
        Math.random() * LOGICAL_WIDTH,
        Math.random() * LOGICAL_HEIGHT
      ]);
    }
    setPoints(newPoints);
    setIteration(0);
    setInertiaHistory([]);
    setPhase('idle');
    setHasStartedClustering(false);
  }, []);

  // Reset model
  const resetModel = useCallback(() => {
    if (points.length === 0) return;

    const newCentroids = initializeCentroids(points, k, initializationMode);
    setCentroids(newCentroids);
    const newAssignments = assignPointsToClusters(points, newCentroids);
    setAssignments(newAssignments);
    setIteration(0);
    setInertiaHistory([]);
    setPhase('idle');
    setHasStartedClustering(false);

    const inertia = calculateInertia(points, newAssignments, newCentroids, true); // Normalize for display
    setInertiaHistory([inertia]);
  }, [points, k, initializationMode]);

  // Step one iteration
  const step = useCallback(() => {
    if (points.length === 0 || centroids.length === 0 || isProcessingRef.current) return;

    setHasStartedClustering(true);
    isProcessingRef.current = true;

    // Assignment phase
    setPhase('assignment');
    const newAssignments = assignPointsToClusters(points, centroids);
    setAssignments(newAssignments);

    setTimeout(() => {
      // Update phase
      setPhase('update');
      const newCentroids = updateCentroids(points, newAssignments, centroids, learningRate);
      setCentroids(newCentroids);

      const inertia = calculateInertia(points, newAssignments, newCentroids, true); // Normalize for display
      setInertiaHistory(prev => [...prev, inertia]);
      setIteration(prev => prev + 1);
      setPhase('assignment');

      isProcessingRef.current = false;
    }, 300);
  }, [points, centroids, learningRate]);

  // Calculate elbow data - only when number of points changes
  const prevPointsLengthRef = useRef(0);
  const pointsRef = useRef(points);
  pointsRef.current = points;

  useEffect(() => {
    if (points.length === 0) {
      setElbowData([]);
      prevPointsLengthRef.current = 0;
      return;
    }

    // Only recalculate if the number of points changed (not just positions)
    if (points.length !== prevPointsLengthRef.current) {
      prevPointsLengthRef.current = points.length;
      setIsCalculatingElbow(true);

      // Use setTimeout to prevent blocking UI
      setTimeout(() => {
        const data = calculateElbowData(pointsRef.current, 10);
        setElbowData(data);
        setIsCalculatingElbow(false);
      }, 100);
    }
  }, [points.length]);

  // Auto-play
  useEffect(() => {
    if (isPlaying && centroids.length > 0) {
      const delay = 1000 / gdSpeed; // Convert speed to delay in ms

      animationTimerRef.current = setTimeout(() => {
        if (!isProcessingRef.current) {
          step();
        }
      }, delay);
    } else {
      if (animationTimerRef.current) {
        clearTimeout(animationTimerRef.current);
      }
    }

    return () => {
      if (animationTimerRef.current) {
        clearTimeout(animationTimerRef.current);
      }
    };
  }, [isPlaying, step, gdSpeed, centroids.length]);

  // Initialize when points or k changes
  const pointsLengthForInitRef = useRef(0);
  useEffect(() => {
    if (points.length > 0) {
      // Only reinitialize if number of points changed (not just positions)
      if (points.length !== pointsLengthForInitRef.current) {
        pointsLengthForInitRef.current = points.length;
        const newCentroids = initializeCentroids(points, k, initializationMode);
        setCentroids(newCentroids);
        const newAssignments = assignPointsToClusters(points, newCentroids);
        setAssignments(newAssignments);
        setIteration(0);
        setInertiaHistory([]);
        setPhase('idle');

        const inertia = calculateInertia(points, newAssignments, newCentroids, true); // Normalize for display
        setInertiaHistory([inertia]);
      }
    }
  }, [points.length, k, initializationMode]);

  // Initial random points - run once on mount
  useEffect(() => {
    if (currentView === 'kmeans' && points.length === 0) {
      generateRandomPoints(100);
    }
  }, [currentView, generateRandomPoints, points.length]);

  // Update point
  const handleUpdatePoint = useCallback((index, newPoint) => {
    setPoints(prev => {
      const updated = [...prev];
      updated[index] = newPoint;
      return updated;
    });
  }, []);

  // Calculate current metrics
  const currentInertia = centroids.length > 0 && points.length > 0
    ? calculateInertia(points, assignments, centroids, true) // Normalize for display
    : 0;

  const mse = currentInertia; // Already normalized, so MSE equals normalized inertia

  // Linear Regression state
  const [lrPoints, setLrPoints] = useState([]);
  const [slope, setSlope] = useState(1.0);
  const [intercept, setIntercept] = useState(0.0);
  const [lrLearningRate, setLrLearningRate] = useState(0.01);
  const [lrSpeed, setLrSpeed] = useState(1);
  const [lrIsPlaying, setLrIsPlaying] = useState(false);
  const [lrIteration, setLrIteration] = useState(0);
  const [lrLossHistory, setLrLossHistory] = useState([]);

  // Animation timer for linear regression
  const lrAnimationTimerRef = useRef(null);
  const lrIsProcessingRef = useRef(false);

  const handleNavigate = (path) => {
    if (path === '/') {
      setCurrentView('home');
    } else if (path === '/kmeans') {
      setCurrentView('kmeans');
    } else if (path === '/linear-regression') {
      setCurrentView('linear-regression');
    }
  };

  const currentPath = currentView === 'home' ? '/' : currentView === 'kmeans' ? '/kmeans' : '/linear-regression';

  // Initialize Linear Regression points
  useEffect(() => {
    if (currentView === 'linear-regression' && lrPoints.length === 0) {
      setLrPoints(generateLRPoints(20, 0, 10, 0, 10));
    }
  }, [currentView, lrPoints.length]);

  const handleUpdateLRPoint = useCallback((index, newPoint) => {
    setLrPoints(prev => {
      const updated = [...prev];
      updated[index] = newPoint;
      return updated;
    });
  }, []);

  // Linear Regression training step
  const lrStep = useCallback(() => {
    if (lrPoints.length === 0 || lrIsProcessingRef.current) return;

    lrIsProcessingRef.current = true;
    const result = gradientDescentStep(lrPoints, slope, intercept, lrLearningRate);

    setSlope(result.newSlope);
    setIntercept(result.newIntercept);
    setLrLossHistory(prev => [...prev, result.loss]);
    setLrIteration(prev => prev + 1);

    lrIsProcessingRef.current = false;
  }, [lrPoints, slope, intercept, lrLearningRate]);

  // Auto-play for linear regression
  useEffect(() => {
    if (lrIsPlaying && lrPoints.length > 0) {
      const delay = 1000 / lrSpeed;

      lrAnimationTimerRef.current = setTimeout(() => {
        if (!lrIsProcessingRef.current) {
          lrStep();
        }
      }, delay);
    } else {
      if (lrAnimationTimerRef.current) {
        clearTimeout(lrAnimationTimerRef.current);
      }
    }

    return () => {
      if (lrAnimationTimerRef.current) {
        clearTimeout(lrAnimationTimerRef.current);
      }
    };
  }, [lrIsPlaying, lrStep, lrSpeed, lrPoints.length]);

  // Calculate Linear Regression metrics
  const lrMSE = lrPoints.length > 0 ? calculateMSE(lrPoints, slope, intercept) : 0;
  const lrRMSE = lrPoints.length > 0 ? calculateRMSE(lrPoints, slope, intercept) : 0;
  const lrMAE = lrPoints.length > 0 ? calculateMAE(lrPoints, slope, intercept) : 0;
  const lrR2 = lrPoints.length > 0 ? calculateR2(lrPoints, slope, intercept) : 0;

  // Home Page View
  if (currentView === 'home') {
    const models = [
      {
        id: 'kmeans',
        name: 'K-Means Clustering',
        description: 'Partition data into K clusters by iteratively updating centroids',
        onClick: () => setCurrentView('kmeans')
      },
      {
        id: 'linear-regression',
        name: 'Linear Regression',
        description: 'Fit a linear model y = mx + b to data points',
        onClick: () => setCurrentView('linear-regression')
      }
    ];

    return (
      <div style={{ 
        minHeight: '100vh', 
        backgroundColor: '#ffffff',
        paddingLeft: '220px',
        paddingTop: '60px',
        fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", "Roboto", "Source Sans Pro", "Inter", "Helvetica Neue", Arial, sans-serif'
      }}>
        <Sidebar currentPath={currentPath} onNavigate={handleNavigate} />
        <NavigationBar onNavigate={handleNavigate} />

