            >
              <span>{section.title}</span>
              <span style={{ fontSize: '18px', color: '#666' }}>
                {expandedSections[section.key] ? '−' : '+'}
              </span>
            </button>
            {expandedSections[section.key] && (
              <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
                {section.items.map((item) => (
