      system_prompt: 'You are a calm news briefing assistant. Return valid JSON only.'
    });

    if (response.success && response.data?.text) {
      const text = response.data.text.trim();
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
